import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classicExampleTrue() {
        // [23,2,4,6,7] k=6: [2,4] sums to 6 (multiple of 6), length 2
        // prefix mod 6: 0,5,1,5,5,0 — remainder 5 recurs at idx=0 and idx=2, dist=2
        assertTrue(new Solution().checkSubarraySum(new int[]{23, 2, 4, 6, 7}, 6));
    }

    @Test
    void distinctRemaindersReturnFalse() {
        // [23,2,6,4,7] k=13: remainders mod 13 are all distinct → false
        assertFalse(new Solution().checkSubarraySum(new int[]{23, 2, 6, 4, 7}, 13));
    }

    @Test
    void twoZerosAlwaysTrue() {
        // [0,0] k=5: [0,0] sums to 0 which is 5*0; length 2
        assertTrue(new Solution().checkSubarraySum(new int[]{0, 0}, 5));
    }

    @Test
    void seedingDistanceGuard() {
        // [1,0,0] k=2: [0,0] at idx 1-2 sums to 0, length 2; earlier remainder 1
        // recurs at idx=1 but dist=1, insufficient — must look further to idx=2, dist=2
        assertTrue(new Solution().checkSubarraySum(new int[]{1, 0, 0}, 2));
    }

    @Test
    void lengthOneShouldNotCount() {
        // [6] k=6: only one element, length < 2
        assertFalse(new Solution().checkSubarraySum(new int[]{6}, 6));
    }

    @Test
    void adjacentSumIsMultiple() {
        // [1,2,3] k=3: [1,2] sums to 3 = 3*1, length 2
        assertTrue(new Solution().checkSubarraySum(new int[]{1, 2, 3}, 3));
    }

    @Test
    void noValidSubarray() {
        // [1,2] k=5: only subarray of length>=2 is [1,2]=3, not multiple of 5
        assertFalse(new Solution().checkSubarraySum(new int[]{1, 2}, 5));
    }
}
